import { type ClassValue, clsx } from "clsx";
import { twMerge } from "tailwind-merge";

/**
 * Standard shadcn class-merge helper. Combines conditional class
 * objects (via clsx) with Tailwind-aware deduping (via tailwind-merge)
 * so `cn("p-2", isActive && "p-4")` resolves to `"p-4"` rather than
 * fighting over both.
 */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}
